// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





function getConditionVisual(condition: string): { emoji: string; icon: string; tone: 'default' | 'info' | 'warning' | 'success' } {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return { emoji: '☀️', icon: 'sun', tone: 'warning' };
  if (normalized.includes('cloud') || normalized.includes('overcast')) return { emoji: '☁️', icon: 'cloud', tone: 'default' };
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return { emoji: '🌧️', icon: 'cloud-rain', tone: 'info' };
  if (normalized.includes('storm') || normalized.includes('thunder')) return { emoji: '⛈️', icon: 'cloud-lightning', tone: 'error' as 'default' };
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice')) return { emoji: '❄️', icon: 'snowflake', tone: 'info' };
  if (normalized.includes('wind') || normalized.includes('breeze')) return { emoji: '💨', icon: 'wind', tone: 'success' };
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return { emoji: '🌫️', icon: 'cloud-fog', tone: 'default' };
  return { emoji: '🌤️', icon: 'cloud-sun', tone: 'default' };
}

function formatTemp(value: number | undefined, unit: string): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--°';
  return `${Math.round(value)}°${unit}`;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedForecastIndex, setSelectedForecastIndex] = useState<number>(0);

  useEffect(() => {
    if (!Array.isArray(props.forecast) || props.forecast.length === 0) {
      setSelectedForecastIndex(0);
      return;
    }
    if (selectedForecastIndex > props.forecast.length - 1) {
      setSelectedForecastIndex(0);
    }
  }, [props.forecast, selectedForecastIndex]);

  const currentVisual = useMemo(() => getConditionVisual(props.condition), [props.condition]);
  const rawForecast = useMemo(() => (Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : []), [props.forecast]);
  const safeForecast = useMemo(() => {
    const normalized = [...rawForecast];
    while (normalized.length < 5) {
      normalized.push({ day: '--', icon: '', high: undefined, low: undefined });
    }
    return normalized;
  }, [rawForecast]);

  const selectedForecast = useMemo(() => {
    if (safeForecast.length === 0) return null;
    return safeForecast[selectedForecastIndex] ?? safeForecast[0];
  }, [safeForecast, selectedForecastIndex]);

  const getForecastVisual = useCallback((iconText?: string) => {
    if (typeof iconText === 'string' && iconText.trim().length > 0) {
      const trimmed = iconText.trim();
      const looksLikeEmoji = /[\u{1F300}-\u{1FAFF}\u2600-\u27BF]/u.test(trimmed);
      if (looksLikeEmoji) return { emoji: trimmed, icon: 'calendar' };
      return getConditionVisual(trimmed);
    }
    return { emoji: '🌤️', icon: 'cloud-sun' };
  }, []);

  const isLoading = !props.city || typeof props.temperature !== 'number' || !props.condition;
  const hasError = typeof props.condition === 'string' && props.condition.toLowerCase().includes('error');

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        radius="xl"
        shadow="md"
        border
      >
        <Stack gap="var(--ggui-spacing-6)">
          {hasError ? (
            <Alert variant="error" title="Unable to load weather">
              Weather data could not be retrieved. Please try again in a moment.
            </Alert>
          ) : null}

          {isLoading ? (
            <Box padding="var(--ggui-spacing-8)">
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Spinner size={20} color="var(--ggui-color-primary-600)" />
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Loading weather data...
                </Text>
              </Row>
            </Box>
          ) : (
            <>
              <Row justify="between" align="center" wrap>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                    Current Weather
                  </Text>
                  <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
                </Stack>
                <Badge variant="primary" size="lg">
                  {props.unit === 'F' ? 'Imperial' : 'Metric'}
                </Badge>
              </Row>

              <Row justify="between" align="center" wrap>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text
                    size="4xl"
                    weight="bold"
                    color="var(--ggui-color-primary-700)"
                  >
                    {formatTemp(props.temperature, props.unit)}
                  </Text>
                  <Row align="center" gap="var(--ggui-spacing-2)">
                    <Text size="2xl" is="span" aria-hidden="true">{currentVisual.emoji}</Text>
                    <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">
                      {props.condition}
                    </Text>
                  </Row>
                </Stack>

                <Stack gap="var(--ggui-spacing-2)">
                  <Box
                    padding="var(--ggui-spacing-4)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                  >
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Icon name="droplets" size={18} color="var(--ggui-color-primary-600)" />
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                      <Spacer size="flex" />
                      <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                    </Row>
                  </Box>
                  <Box
                    padding="var(--ggui-spacing-4)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                  >
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Icon name="wind" size={18} color="var(--ggui-color-primary-600)" />
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
                      <Spacer size="flex" />
                      <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text>
                    </Row>
                  </Box>
                </Stack>
              </Row>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Stack gap="var(--ggui-spacing-3)">
                <Row justify="between" align="center">
                  <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
                  {selectedForecast ? (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      Selected: {selectedForecast.day ?? 'N/A'} · High {formatTemp(selectedForecast.high, props.unit)} / Low {formatTemp(selectedForecast.low, props.unit)}
                    </Text>
                  ) : null}
                </Row>

                {rawForecast.length === 0 ? (
                  <Alert variant="info" title="Forecast unavailable">
                    No forecast data is available right now.
                  </Alert>
                ) : (
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {safeForecast.map((item, index) => {
                      const visual = getForecastVisual(item.icon);
                      const active = selectedForecastIndex === index;
                      return (
                        <Button
                          key={`${item.day ?? 'day'}-${index}`}
                          variant={active ? 'primary' : 'secondary'}
                          size="md"
                          onPress={() => setSelectedForecastIndex(index)}
                          aria-label={`${item.day ?? 'Day'}, ${typeof item.icon === 'string' && item.icon.trim().length > 0 ? item.icon : 'weather'}, high ${formatTemp(item.high, props.unit)}, low ${formatTemp(item.low, props.unit)}`}
                        >
                          <Stack gap="var(--ggui-spacing-1)" align="center">
                            <Text variant="label" color="var(--ggui-color-onSurface)">{item.day ?? 'Day'}</Text>
                            <Text size="xl" is="span" aria-hidden="true">{visual.emoji}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                              {formatTemp(item.high, props.unit)} / {formatTemp(item.low, props.unit)}
                            </Text>
                          </Stack>
                        </Button>
                      );
                    })}
                  </Row>
                )}
              </Stack>
            </>
          )}
        </Stack>
      </Card>
    </Container>

  );
}

