import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string; clientTempId?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string }>>([]);
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [isHydrating, setIsHydrating] = useState<boolean>(true);
  const pendingCreateMapRef = useRef<Record<string, string>>({});

  const normalizedColumns = useMemo(() => {
    const source = (props.columns || []).map((column, index) => ({
      id: (column.id || `column-${index}`).toLowerCase(),
      name: column.name || `Column ${index + 1}`
    }));
    const findById = (id: string) => source.find((column) => column.id === id);
    return [
      findById('todo') || { id: 'todo', name: 'To Do' },
      findById('in-progress') || { id: 'in-progress', name: 'In Progress' },
      findById('done') || { id: 'done', name: 'Done' }
    ];
  }, [props.columns]);

  const canonicalColumnIds = useMemo(() => normalizedColumns.map((column) => column.id), [normalizedColumns]);
  const todoColumnId = useMemo(() => (canonicalColumnIds.includes('todo') ? 'todo' : (canonicalColumnIds[0] || 'todo')), [canonicalColumnIds]);
  const doneColumnId = useMemo(() => (canonicalColumnIds.includes('done') ? 'done' : (canonicalColumnIds[2] || 'done')), [canonicalColumnIds]);

  const normalizeColumnId = useCallback((rawColumn?: string) => {
    if (rawColumn) {
      const normalizedRaw = rawColumn.toLowerCase();
      if (canonicalColumnIds.includes(normalizedRaw)) return normalizedRaw;
    }
    return todoColumnId;
  }, [canonicalColumnIds, todoColumnId]);
  useEffect(() => {
    const normalized = (props.tasks || []).map((task, index) => ({
      id: task.id || `task-${index}` ,
      title: task.title || 'Untitled task',
      priority: task.priority || 'medium',
      assignee: task.assignee || 'NA',
      column: normalizeColumnId(task.column),
      dueDate: task.dueDate || ''
    }));
    setBoardTasks((prev) => {
      const prevById: Record<string, { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string }> = {};
      prev.forEach((task) => { prevById[task.id] = task; });
      const merged = normalized.map((task) => {
        if (editingTaskId && task.id === editingTaskId) {
          const local = prevById[task.id];
          if (local) {
            return { ...task, ...local, title: editingTitle || local.title };
          }
          return { ...task, title: editingTitle || task.title };
        }
        return prevById[task.id] ? { ...task, ...prevById[task.id] } : task;
      });
      prev.forEach((task) => {
        if (!merged.find((item) => item.id === task.id)) {
          merged.push(task);
        }
      });
      return merged;
    });
    setIsHydrating(false);
  }, [props.tasks, normalizeColumnId, editingTaskId, editingTitle]);

  const processedStreamIndexRef = useRef<number>(0);

  useEffect(() => {
    const events = taskChanged.all || [];
    if (processedStreamIndexRef.current >= events.length) return;

    const unseen = events.slice(processedStreamIndexRef.current);
    processedStreamIndexRef.current = events.length;

    unseen.forEach((event) => {
      if (!event || !event.task) return;
      const incoming = event.task;
      const incomingId = incoming.id;
      if (!incomingId && event.action === 'delete') return;
      if (!incomingId) return;

      const incomingTask = {
        id: incomingId,
        title: incoming.title || 'Untitled task',
        priority: incoming.priority || 'medium',
        assignee: incoming.assignee || 'NA',
        column: normalizeColumnId(incoming.column),
        dueDate: incoming.dueDate || ''
      };

      setBoardTasks((prev) => {
        if (event.action === 'delete') {
          return prev.filter((task) => task.id !== incomingId);
        }

        let working = prev;
        const clientTempId = incoming.id && pendingCreateMapRef.current[incoming.id] ? incoming.id : '';
        if (clientTempId) {
          working = prev.filter((task) => task.id !== clientTempId);
          delete pendingCreateMapRef.current[clientTempId];
        }

        const existingIndex = working.findIndex((task) => task.id === incomingId);
        if (existingIndex === -1) {
          return [...working, incomingTask];
        }

        const next = [...working];
        const existing = next[existingIndex];
        if (editingTaskId && incomingId === editingTaskId) {
          next[existingIndex] = {
            ...existing,
            ...incomingTask,
            title: existing.title
          };
          return next;
        }
        next[existingIndex] = { ...existing, ...incomingTask };
        return next;
      });
    });
  }, [taskChanged.all, normalizeColumnId, editingTaskId]);
  const getPriorityVariant = useCallback((priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' => {
