    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const moveTask = useCallback(async (taskId: string, nextColumn: string) => {
    const validNextColumn = normalizeColumnId(nextColumn);
    const currentTask = boardTasks.find((task) => task.id === taskId);
    if (!currentTask || currentTask.column === validNextColumn) return;
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: validNextColumn } : task)));
    try {
      await Promise.resolve(taskUpdate({ action: 'move', taskId, data: { column: validNextColumn } }));
      setErrorMessage('');
    } catch (error) {
      setErrorMessage('Failed to move task. Please try again.');
    }
  }, [taskUpdate, normalizeColumnId, boardTasks]);

  const saveEdit = useCallback(async (taskId: string) => {
    const finalTitle = editingTitle.trim();
    if (!finalTitle) return;
    const currentTask = boardTasks.find((task) => task.id === taskId);
    if (!currentTask) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    if (finalTitle === currentTask.title) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    const updatedTask: { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string } = {
      id: currentTask.id,
      title: finalTitle,
      priority: currentTask.priority,
      assignee: currentTask.assignee,
      column: currentTask.column,
      dueDate: currentTask.dueDate
    };
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? updatedTask : task)));
    try {
      await Promise.resolve(taskUpdate({
        action: 'edit',
        taskId,
        data: {
          column: updatedTask.column,
          title: updatedTask.title
        }
      }));
      setErrorMessage('');
    } catch (error) {
      setErrorMessage('Failed to save task changes.');
    }
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, taskUpdate, boardTasks]);

  const createTask = useCallback(async (columnId: string) => {
    const title = newTaskTitle.trim();
    if (!title) return;
    const validColumn = normalizeColumnId(columnId || todoColumnId);
    const newId = `task-${Date.now()}`;
    const created = {
      id: newId,
      title,
      priority: newTaskPriority,
      assignee: 'NA',
      column: validColumn,
      dueDate: ''
    };
    setBoardTasks((prev) => [...prev, created]);
    pendingCreateMapRef.current[newId] = newId;
    try {
      await Promise.resolve(taskUpdate({
        action: 'create',
        taskId: newId,
        data: {
          column: created.column,
          title: created.title,
          priority: created.priority,
          assignee: created.assignee,
          dueDate: created.dueDate,
          clientTempId: newId
        }
      }));
      setErrorMessage('');
    } catch (error) {
      setErrorMessage('Failed to create task.');
    }
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId('');
  }, [newTaskTitle, newTaskPriority, taskUpdate, normalizeColumnId, todoColumnId]);

  const totalTasks = boardTasks.length;
  const completedTasks = boardTasks.filter((task) => task.column === doneColumnId).length;
  return (
