      await Promise.resolve(addToCart({ productId: productId, quantity: quantity }));
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unable to add item to cart.';
      setSubmitError(message);
    } finally {
      setIsSubmitting(false);
