                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    {safeStock} available
                  </Text>
                </Row>
              </Stack>
            </Box>

            <Tabs
              activeKey={activeTab}
              onChange={setActiveTab}
              variant="line"
              items={[
                {
