                      })}
                    />
                  ) : (
                    <Alert variant="info" title="No specifications">
                      Specifications are not available for this product.
                    </Alert>
                  ),
                },
                {
                  key: 'reviews',
                  label: 'Reviews',
                  content: safeReviews.length > 0 ? (
                    <Stack gap="var(--ggui-spacing-4)">
                      {safeReviews.map((review, index) => {
                        const reviewRecord = review as Record<string, unknown>;
                        const reviewRating = Math.max(0, Math.min(5, Math.round(Number(reviewRecord?.rating ?? 0))));
                        const reviewDate = String(reviewRecord?.date ?? '');
                        return (
                          <Card key={`review-${index}`} padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center" wrap>
                                <Text weight="semibold" color="var(--ggui-color-onSurface)">
                                  {String(reviewRecord?.author ?? 'Anonymous')}
                                </Text>
                                <Text is="span" variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  <time dateTime={reviewDate}>{reviewDate}</time>
                                </Text>
                              </Row>
