                                    name={starIndex < reviewRating ? 'star' : 'star-off'}
                                    size={14}
                                    aria-hidden
                                    color={
                                      starIndex < reviewRating
                                        ? 'var(--ggui-color-warning-500)'
                                        : 'var(--ggui-color-outline)'
                                    }
                                  />
                                ))}
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {`${reviewRating} out of 5 stars`}
                                </Text>
                              </Row>
                              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                                {String(reviewRecord?.text ?? '')}
                              </Text>
                            </Stack>
                          </Card>
                        );
                      })}
                    </Stack>
                  ) : (
                    <Alert variant="info" title="No reviews yet">
                      Be the first to review this product.
                    </Alert>
                  ),
                },
              ]}
            />

            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Stack gap="var(--ggui-spacing-3)">
                {submitError ? (
                  <Alert variant="error" title="Could not add to cart">
                    {submitError}
                  </Alert>
                ) : null}
                <Row justify="between" align="center" wrap gap="var(--ggui-spacing-4)">
                  <Row align="end" gap="var(--ggui-spacing-2)">
                    <Input
                      label="Quantity"
                      type="number"
                      value={String(quantity)}
                      onChange={(value) => {
                        const parsed = Number(value);
                        if (Number.isNaN(parsed)) {
                          setQuantity(1);
                          return;
                        }
                        if (safeStock <= 0) {
                          setQuantity(1);
                          return;
                        }
                        setQuantity(Math.max(1, Math.min(safeStock, Math.round(parsed))));
                      }}
                    />
                    <Button
                      as={Clickable}
                      onClick={decrementQuantity}
                      variant="outline"
                      size="sm"
                      aria-label="Decrease quantity"
                      disabled={quantity <= 1 || isSubmitting}
                    >
                      -
                    </Button>
                    <Button
                      as={Clickable}
                      onClick={incrementQuantity}
                      variant="outline"
                      size="sm"
                      aria-label="Increase quantity"
                      disabled={isOutOfStock || quantity >= safeStock || isSubmitting}
                    >
                      +
                    </Button>
                  </Row>

                  <Button
                    as={Clickable}
                    onClick={handleAddToCart}
                    variant="primary"
                    size="md"
                    loading={isSubmitting}
                    disabled={isOutOfStock || !productId || isSubmitting}
                  >
                    {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
                  </Button>
                </Row>
              </Stack>
            </Box>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );


}

