      setStockMap((prev) => {
        const next = { ...prev };
        validUpdates.forEach((item) => {
          const symbol = item.symbol ?? '';
          if (!symbol) return;
          const existing = next[symbol] ?? {
            symbol,
            name: 'Unknown Company',
            price: 0,
            change: 0,
            changePercent: 0,
          };
          next[symbol] = {
            ...existing,
            symbol,
            price: item.price ?? existing.price,
            change: item.change ?? existing.change,
            changePercent: item.changePercent ?? existing.changePercent,
          };
        });
        return next;
      });

      setIsLoading(false);
      setStreamError(null);

      validUpdates.forEach((item) => {
        const updatedSymbol = item.symbol ?? '';
        if (!updatedSymbol) return;
        setFlashMap((prev) => ({ ...prev, [updatedSymbol]: true }));
        setTimeout(() => {
          setFlashMap((prev) => ({ ...prev, [updatedSymbol]: false }));
        }, 600);
      });

      const latestEventTime = validUpdates
        .map((item) => (item.timestamp ? new Date(item.timestamp) : null))
        .filter((d): d is Date => d !== null && !Number.isNaN(d.getTime()))
        .sort((a, b) => b.getTime() - a.getTime())[0];
      setLastUpdated(latestEventTime ?? new Date());
    } catch (_error) {
      setStreamError('Unable to process live price update.');
    }
  }, [priceUpdate.latest]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!marketStatus.latest?.timestamp) return;
    const statusTime = new Date(marketStatus.latest.timestamp);
    if (!Number.isNaN(statusTime.getTime())) {
      setLastUpdated((prev) => (statusTime.getTime() > prev.getTime() ? statusTime : prev));
      setIsLoading(false);
      setStreamError(null);
    } else {
      setStreamError('Unable to process market status timestamp.');
    }
  }, [marketStatus.latest]);

  const stocksList = useMemo(() => Object.values(stockMap), [stockMap]);

  const marketStatusText = marketStatus.latest?.status ?? 'open';
  const marketTimeText = marketStatus.latest?.timestamp ?? '';
  const formatPrice = useCallback((value: number) => `$${value.toFixed(2)}`, []);
  const formatChange = useCallback((value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}`, []);
  const formatPercent = useCallback((value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          radius="lg"
          shadow="sm"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant)',
            borderColor: 'var(--ggui-color-outline)',
          }}
        >
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Box style={{ color: 'var(--ggui-color-onSurfaceVariant)' }} aria-live="polite" aria-atomic="true" role="status">
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Last Updated: {lastUpdated.toLocaleTimeString()}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Live Clock: {now.toLocaleTimeString()}
                </Text>
              </Box>
            </Stack>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Badge
                variant={marketStatusText === 'open' ? 'success' : marketStatusText === 'closed' ? 'error' : 'warning'}
              >
                {marketStatusText}
              </Badge>
              {marketTimeText ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {marketTimeText}
                </Text>
              ) : null}
            </Stack>
          </Row>
        </Card>

        {streamError ? (
          <Alert variant="error" title="Live update error">
            {streamError}
          </Alert>
        ) : null}

        {isLoading ? (
          <Card padding="var(--ggui-spacing-6)" radius="lg" shadow="sm" border>
            <Row align="center" gap="var(--ggui-spacing-2)" role="status" aria-live="polite" aria-atomic="true">
              <Spinner size={20} color="var(--ggui-color-primary-600)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Loading market data...
              </Text>
            </Row>
          </Card>

        ) : stocksList.length === 0 ? (
          <Alert variant="info" title="No stock data">
            Waiting for stock symbols and prices.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap="var(--ggui-spacing-4)">
            {stocksList.map((stock) => {
              const isPositive = stock.change >= 0;
              const trendColor = isPositive
                ? 'var(--ggui-color-success)'
                : 'var(--ggui-color-error)';
              return (
                <Card
                  key={stock.symbol}
                  padding="var(--ggui-spacing-6)"
                  radius="lg"
                  shadow={flashMap[stock.symbol] ? 'md' : 'sm'}
                  border
                  style={{
                    borderColor: trendColor,
                    background: flashMap[stock.symbol]
                      ? isPositive
                        ? 'var(--ggui-color-success-100, #dcfce7)'
                        : 'var(--ggui-color-error-100, #fee2e2)'
                      : 'var(--ggui-color-surface, #ffffff)',
                    animation: flashMap[stock.symbol] ? 'ggui-fadeIn 300ms ease-out' : 'none',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Heading level={2} color="var(--ggui-color-onSurface)">
                      {stock.symbol}
                    </Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name}
                    </Text>
                    <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                      {formatPrice(stock.price)}
                    </Text>
                    <Row justify="between" align="center">
                      <Text variant="bodySmall" color={trendColor}>
                        {formatChange(stock.change)}
                      </Text>
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color={trendColor}
                        is="span"
                        aria-label={`Trend ${isPositive ? 'up' : 'down'} ${formatPercent(stock.changePercent)}`}
                      >
                        {isPositive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                      </Text>
                    </Row>

                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}

        <Box aria-live="polite" aria-atomic="true" role="status">
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Stream updates received: {priceUpdate.all.length}
          </Text>
        </Box>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const availableAvatars = useMemo(() => {
    const fallbackAvatars = ['😀', '🧑‍💻', '🎨', '🚀'];
    const source = props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions : fallbackAvatars;
    const uniqueAvatars = source.filter((item, index) => source.indexOf(item) === index);
    const normalized = [...uniqueAvatars, ...fallbackAvatars].slice(0, 4);
    return normalized;
  }, [props.avatarOptions]);

  const availableRoles = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? (availableAvatars[0] ?? '😀'));
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const nameError = trimmedName.length === 0 ? 'Name is required' : '';
  const emailError = trimmedEmail.length === 0 ? 'Email is required' : emailRegex.test(trimmedEmail) ? '' : 'Please enter a valid email address';

  const isStep1Valid = nameError === '' && emailError === '' && avatar.length > 0;
  const isStep2Valid = role.length > 0 && (theme === 'light' || theme === 'dark');
  const canGoNext = step === 1 ? isStep1Valid : step === 2 ? true : true;
  const progressValue = (step / 3) * 100;

  useEffect(() => {
    if (!availableAvatars.includes(avatar)) {
      setAvatar(availableAvatars[0] ?? '😀');
    }
  }, [availableAvatars, avatar]);

  useEffect(() => {
    if (role && !availableRoles.includes(role)) {
      setRole('');
    }
  }, [availableRoles, role]);

  const handleNext = useCallback(() => {
    if (!canGoNext) {
      return;
    }
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canGoNext]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) {
      return;
    }
    const payload: ActionCompletePayload = {
      name: trimmedName,
      email: trimmedEmail,
      avatar,
      role,
      emailNotifications,
      theme,
    };
    if ((props as unknown as { onComplete?: (data: ActionCompletePayload) => void }).onComplete) {
      (props as unknown as { onComplete: (data: ActionCompletePayload) => void }).onComplete(payload);
      return;
    }
    complete(payload);
  }, [isStep1Valid, isStep2Valid, trimmedName, trimmedEmail, avatar, role, emailNotifications, theme, props, complete]);
  const roleSelectOptions = useMemo(() => availableRoles.map((r) => ({ value: r, label: r })), [availableRoles]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          radius="xl"
          shadow="md"
          border
        >
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={1}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" aria-label="Onboarding progress" aria-valuetext={`Step ${step} of 3`} />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {step === 1 ? 'Set up your profile details.' : step === 2 ? 'Choose your preferences.' : 'Review and confirm your setup.'}
            </Text>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          radius="xl"
          shadow="sm"
          border
        >
          <Box>
            <Box
              key={`step-${step}`}
              style={{
                animation: 'ggui-fadeIn 200ms ease-out',
                transition: 'opacity 200ms ease-in-out, transform 200ms ease-in-out'
              }}
            >
              {step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={2}>Profile Setup</Heading>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Enter your full name"
                    required
                    error={name.length > 0 || step > 1 ? nameError : ''}
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    required
                    error={email.length > 0 || step > 1 ? emailError : ''}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text id="avatar-group-label" variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose Avatar</Text>
                    <Box role="radiogroup" aria-labelledby="avatar-group-label">
                      <Row
                        gap="var(--ggui-spacing-2)"
                        wrap
                      >
                        {availableAvatars.map((option, index) => (
                          <Box key={option} padding="var(--ggui-spacing-1)">
                            <Card
                              as={Clickable}
                              onClick={() => setAvatar(option)}
                              onKeyDown={(event: React.KeyboardEvent) => {
                                if (event.key === 'Enter' || event.key === ' ') {
                                  event.preventDefault();
                                  setAvatar(option);
                                  return;
                                }
                                if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
                                  event.preventDefault();
                                  const nextIndex = (index + 1) % availableAvatars.length;
                                  setAvatar(availableAvatars[nextIndex]);
                                }
                                if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
                                  event.preventDefault();
                                  const prevIndex = (index - 1 + availableAvatars.length) % availableAvatars.length;
                                  setAvatar(availableAvatars[prevIndex]);
                                }
                              }}
                              role="radio"
                              aria-checked={avatar === option}
                              aria-label={`Select avatar ${option}`}
                              tabIndex={0}
                              padding="var(--ggui-spacing-4)"
                              radius="lg"
                              border
                              shadow="none"
                              background={avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)'}
                            >
                              <Stack align="center" gap="var(--ggui-spacing-1)">
                                <Text size="2xl">{option}</Text>
                                {avatar === option && <Badge variant="success" size="sm">Selected</Badge>}
                              </Stack>
                            </Card>
                          </Box>
                        ))}
                      </Row>
                    </Box>
                  </Stack>
                )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={2}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={roleSelectOptions}
                    placeholder="Select your role"
                    required
                    error={role.length === 0 && step > 1 ? 'Role is required' : ''}
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Toggle
                    label="Dark theme"
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    Current theme: {theme === 'dark' ? 'Dark' : 'Light'}
                  </Text>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={2}>Review &amp; Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" radius="lg" shadow="none" border>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between" align="start" wrap gap="var(--ggui-spacing-2)">
                        <Text variant="label">Avatar:</Text>
                        <Text>{avatar}</Text>
                      </Row>
                      <Row justify="between" align="start" wrap gap="var(--ggui-spacing-2)">
                        <Text variant="label">Name:</Text>
                        <Text>{trimmedName || '—'}</Text>
                      </Row>
                      <Row justify="between" align="start" wrap gap="var(--ggui-spacing-2)">
                        <Text variant="label">Email:</Text>
                        <Text>{trimmedEmail || '—'}</Text>
                      </Row>
                      <Row justify="between" align="start" wrap gap="var(--ggui-spacing-2)">
                        <Text variant="label">Role:</Text>
                        <Text>{role || '—'}</Text>
                      </Row>
                      <Row justify="between" align="start" wrap gap="var(--ggui-spacing-2)">
                        <Text variant="label">Email Notifications:</Text>
                        <Text>{emailNotifications ? 'On' : 'Off'}</Text>
                      </Row>
                      <Row justify="between" align="start" wrap gap="var(--ggui-spacing-2)">
                        <Text variant="label">Theme:</Text>
                        <Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text>
                      </Row>
                    </Stack>
                  </Card>
                </Stack>
              )}
            </Box>
          </Box>
          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              {step === 3 ? 'Go Back' : 'Back'}
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleComplete} disabled={!isStep1Valid || !isStep2Valid}>
                  Complete Setup
                </Button>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>


  );
}
